det_check_template:
proof fn det_new<T>(val: T, f: spec_fn(T) -> bool, r1: InvCell<T>, r2: InvCell<T>)
    requires (f(val)),
    ensures
        ({
            &&& (forall|v| f(v) <==> r1.inv(v))
            &&& (forall|v| f(v) <==> r2.inv(v))
        }) ==> det_new_equal::<T>(r1, r2),
{
    reveal(InvCellPred::inv);
{ASSUMES}}

equal_fn_def:
// Generated equal-fn for determinism check.
// Policy: errs_equivalent=True, opaque_ok=False
spec fn det_new_equal<T>(r1: InvCell<T>, r2: InvCell<T>) -> bool {
    (r1 == r2)
}
